    {{#compare daysSinceLastReview "==" 30}}
        <span style="background-color: yellow">Due TODAY</span>
    {{else}}
        {{#compare daysSinceLastReview ">" 30}}
            <span style="color: red">Overdue<br>(interval 30 days, elapsed {{daysSinceLastReview}} days)</span>
        {{else}}
            <span style="color: green">Not due yet<br>(interval 30 days, elapsed {{daysSinceLastReview}} days)</span>
        {{/compare}}
    {{/compare}}
{{else}}

{{#compare reviewInterval "==" "3 months"}}
    {{#compare daysSinceLastReview "==" 90}}
        <span style="background-color: yellow">Due TODAY</span>
    {{else}}
        {{#compare daysSinceLastReview ">" 90}}
            <span style="color: red">Overdue<br>(interval 90 days, elapsed {{daysSinceLastReview}} days)</span>
        {{else}}
            <span style="color: green">Not due yet<br>(interval 90 days, elapsed {{daysSinceLastReview}} days)</span>
        {{/compare}}
    {{/compare}}
{{else}}

{{#compare reviewInterval "==" "6 months"}}
