  .tags-list {
    display: flex;
    flex-wrap: wrap;
    gap: 6px;
  }

  .simpletags {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-height: 24px;
    padding: 0 8px;
    border-radius: 999px;
    box-sizing: border-box;
    text-decoration: none;
    white-space: nowrap;
    font-size: 12px;
    line-height: 1;
    font-weight: 600;
    border: 1px solid {{@root.theme.palette.themeTertiary}};
    background: {{@root.theme.palette.themeLighter}};
    color: {{@root.theme.palette.themeDarker}};
    transition: transform 120ms ease, box-shadow 120ms ease, background 120ms ease;
  }

  .simpletags:hover {
    text-decoration: none;
    transform: translateY(-1px);
    background: {{@root.theme.palette.themeLight}};
    box-shadow: 0 1px 3px rgba(0,0,0,.12);
  }

  .simpletags:active {
    transform: translateY(0);
  }
</style>

<div class="tags">
  <pnp-icon data-name="Tag" aria-hidden="true" data-theme-variant="{{JSONstringify @root.theme}}"></pnp-icon>

