                        data-interception="off"
                        href="?v=Cards{{#if (getUrlParameter "k")}}&k={{getUrlParameter "k"}}{{/if}}&f_03b3d4b9-84a9-4adf-8524-ded7a8646f9d=%5B%7B%22filterName%22%3A%22RefinableString128%22%2C%22values%22%3A%5B%7B%22name%22%3A%22{{label}}%22%2C%22value%22%3A%22or({{itemAt gp0Parts 0}}%7C%23{{itemAt gp0Parts 1}}%2C{{itemAt l0Parts 0}}%7C%23{{itemAt l0IdParts 1}})%22%2C%22operator%22%3A0%7D%5D%2C%22operator%22%3A%22or%22%7D%5D#"
                      >
                        {{label}}
